#include<bits/stdc++.h>
using namespace std;
int mp[550][550],flag[550];
vector<int> ans;
int in[550];
void dfs(int x)
{
    for(int i=1;i<=500;i++)
    {
        if(mp[x][i])
        {
            mp[x][i]--;
            mp[i][x]--;
            dfs(i);
        }
    }
    ans.push_back(x);
}
int main()
{
    int m;
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x][y]++;
        mp[y][x]++;
        flag[x]=flag[y]=1;
        in[x]++;
        in[y]++;
    }
    int flag1=0;
    for(int i=1;i<=500;i++)
    {
        if(in[i]%2==1)
        {
            flag1=1;
            dfs(i);
            break;
        }
    }
    if(flag1==0)
    {
        for(int i=1;i<=500;i++)
        {
            if(flag[i])
            {
                dfs(i);
                break;
            }
        }
    }
    reverse(ans.begin(),ans.end());
    for(int i:ans)
    {
        printf("%d\n",i);
    }
    return 0;
}
